import{_ as e,o as d,c as i,ao as l}from"./chunks/framework.15pdmnck.js";const x=JSON.parse('{"title":"MATLAB → Julia idiom mapping","description":"","frontmatter":{},"headers":[],"relativePath":"idioms.md","filePath":"idioms.md","lastUpdated":null}'),r={name:"idioms.md"};function a(g,t,s,n,o,c){return d(),i("div",null,[...t[0]||(t[0]=[l('<p>&lt;!– GENERATED from src/idioms.jl by Mjolnir.write_idioms — do not edit by hand. –&gt;</p><h1 id="MATLAB-Julia-idiom-mapping" tabindex="-1">MATLAB → Julia idiom mapping <a class="header-anchor" href="#MATLAB-Julia-idiom-mapping" aria-label="Permalink to &quot;MATLAB → Julia idiom mapping {#MATLAB-Julia-idiom-mapping}&quot;">​</a></h1><p>Normative MATLAB→Julia mappings. <code>✅</code> implemented · <code>🟡</code> partial/divergence · <code>⬜</code> planned. Canonical source: <code>src/idioms.jl</code>. Machine-readable mirror: <code>docs/idioms.json</code>.</p><h2 id="Literals-and-types" tabindex="-1">Literals &amp; types <a class="header-anchor" href="#Literals-and-types" aria-label="Permalink to &quot;Literals &amp; types {#Literals-and-types}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>42 / 2.5 / 1e3</code></td><td style="text-align:right;"><code>42 / 2.5 / 1e3</code></td><td style="text-align:right;">integer literals stay Int</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[1 2 3] (row)</code></td><td style="text-align:right;"><code>[1 2 3] (1×N Matrix)</code></td><td style="text-align:right;">MATLAB-faithful: size(x,2), transpose, x*y, and [A b] concatenation all work</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[1;2;3] (column)</code></td><td style="text-align:right;"><code>[1, 2, 3] (Vector)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[1 2; 3 4]</code></td><td style="text-align:right;"><code>[1 2; 3 4] (Matrix)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[A b] / [A; b]</code></td><td style="text-align:right;"><code>hcat / vcat (concatenation)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>0x1F</code></td><td style="text-align:right;"><code>0x1f -&gt; Int</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>3i</code></td><td style="text-align:right;"><code>3.0im</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>&#39;text&#39; (char array)</code></td><td style="text-align:right;"><code>&quot;text&quot;</code></td><td style="text-align:right;">char-array semantics approximated by String</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>&quot;text&quot;</code></td><td style="text-align:right;"><code>&quot;text&quot;</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>true / false</code></td><td style="text-align:right;"><code>true / false</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>pi / Inf / NaN / eps / i,j</code></td><td style="text-align:right;"><code>pi / Inf / NaN / eps() / im</code></td><td style="text-align:right;">only when not shadowed by a variable</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>... (line continuation)</code></td><td style="text-align:right;"><code>(transparent)</code></td><td style="text-align:right;">ignored, as in MATLAB</td></tr></tbody></table><h2 id="Operators" tabindex="-1">Operators <a class="header-anchor" href="#Operators" aria-label="Permalink to &quot;Operators {#Operators}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>+ -</code></td><td style="text-align:right;"><code>.+ .-</code></td><td style="text-align:right;">MATLAB implicit expansion; de-broadcast to +/- when both operands are scalar</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>* / \\ ^</code></td><td style="text-align:right;"><code>* / \\ ^</code></td><td style="text-align:right;">matrix operators</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>.* ./ .^ .\\</code></td><td style="text-align:right;"><code>.* ./ .^ .\\</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>== ~= &lt; &gt; &lt;= &gt;=</code></td><td style="text-align:right;"><code>.== .!= .&lt; .&gt; .&lt;= .&gt;=</code></td><td style="text-align:right;">broadcast; de-broadcast when scalar</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;">`&amp;</td><td style="text-align:right;">`</td><td style="text-align:right;">`.&amp; .</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;">`&amp;&amp;</td><td style="text-align:right;"></td><td style="text-align:right;">`</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>~x</code></td><td style="text-align:right;"><code>.!x</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>x&#39;</code></td><td style="text-align:right;"><code>x&#39;</code></td><td style="text-align:right;">adjoint</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>x.&#39;</code></td><td style="text-align:right;"><code>transpose(x)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>a:b / a:s:b</code></td><td style="text-align:right;"><code>a:b / a:s:b</code></td><td style="text-align:right;"></td></tr></tbody></table><h2 id="Indexing" tabindex="-1">Indexing <a class="header-anchor" href="#Indexing" aria-label="Permalink to &quot;Indexing {#Indexing}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>x(i), x(i,j)</code></td><td style="text-align:right;"><code>x[i], x[i,j]</code></td><td style="text-align:right;">only when x is a known variable (scope pre-pass)</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>f(a,b) (f not a variable)</code></td><td style="text-align:right;"><code>f(a, b)</code></td><td style="text-align:right;">resolved as a call</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>x(end), x(2:end)</code></td><td style="text-align:right;"><code>x[end], x[2:end]</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>x(:), A(2,:)</code></td><td style="text-align:right;"><code>x[:], A[2, :]</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>x(i) = v</code></td><td style="text-align:right;"><code>x[i] = v</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>s.field</code></td><td style="text-align:right;"><code>s.field</code></td><td style="text-align:right;"></td></tr></tbody></table><h2 id="Shapes-and-reductions" tabindex="-1">Shapes &amp; reductions <a class="header-anchor" href="#Shapes-and-reductions" aria-label="Permalink to &quot;Shapes &amp; reductions {#Shapes-and-reductions}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>numel(x)</code></td><td style="text-align:right;"><code>length(x)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>length(x)</code></td><td style="text-align:right;"><code>maximum(size(x))</code></td><td style="text-align:right;">MATLAB length = longest dim; errors on a scalar</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>size(x,d)</code></td><td style="text-align:right;"><code>size(x, d)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>sum(A)/prod(A) on a matrix</code></td><td style="text-align:right;"><code>sum(A, dims=1)/prod(A, dims=1)</code></td><td style="text-align:right;">first-dim reduction when A is provably a matrix; vectors stay scalar</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>max(A)/min(A) on a matrix</code></td><td style="text-align:right;"><code>maximum(A, dims=1)/minimum(A, dims=1)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>max(a,b)/min(a,b)</code></td><td style="text-align:right;"><code>max.(a, b)/min.(a, b)</code></td><td style="text-align:right;"></td></tr></tbody></table><h2 id="Constructors-and-builtins" tabindex="-1">Constructors &amp; builtins <a class="header-anchor" href="#Constructors-and-builtins" aria-label="Permalink to &quot;Constructors &amp; builtins {#Constructors-and-builtins}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>zeros(n)/ones(n)/rand(n)</code></td><td style="text-align:right;"><code>zeros(n,n)/...</code></td><td style="text-align:right;">MATLAB zeros(n) is n×n</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>eye(n)</code></td><td style="text-align:right;"><code>Matrix{Float64}(LinearAlgebra.I, n, n)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>inv(A)</code></td><td style="text-align:right;"><code>inv(A)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>linspace(a,b,n)</code></td><td style="text-align:right;"><code>range(a, b, length=n)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>repmat(A,m,n)</code></td><td style="text-align:right;"><code>repeat(A, m, n)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>find(x)</code></td><td style="text-align:right;"><code>findall(!iszero, x)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>disp(x)</code></td><td style="text-align:right;"><code>println(x)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>sqrt/abs/exp/log/sin/.../mod/rem/fix</code></td><td style="text-align:right;"><code>f.(args) (broadcast)</code></td><td style="text-align:right;">element-wise math; de-broadcast when scalar</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>isnan/isinf/isfinite</code></td><td style="text-align:right;"><code>isnan.(x)/isinf.(x)/isfinite.(x)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>fieldnames(s)</code></td><td style="text-align:right;"><code>collect(string.(keys(s)))</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>isfield(s,&#39;a&#39;)</code></td><td style="text-align:right;"><code>haskey(s, Symbol(&quot;a&quot;))</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>rmfield(s,&#39;a&#39;)</code></td><td style="text-align:right;"><code>Base.structdiff(s, (a = nothing,))</code></td><td style="text-align:right;">literal field name only</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>warning(msg)</code></td><td style="text-align:right;"><code>@warn msg</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>s.(f) (dynamic field)</code></td><td style="text-align:right;"><code>getproperty(s, Symbol(f)) / merge(...)</code></td><td style="text-align:right;">read + write</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>s(i).field (struct array)</code></td><td style="text-align:right;"><code>s[i] = merge(s[i], (field=v,)) / s[i].field</code></td><td style="text-align:right;">read works; build-from-scratch needs a preallocated Vector</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>ge/le/gt/lt/eq/ne</code></td><td style="text-align:right;"><code>.&gt;= / .&lt;= / .&gt; / .&lt; / .== / .!=</code></td><td style="text-align:right;">functional comparison forms</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>double/single/logical</code></td><td style="text-align:right;"><code>Float64. / Float32. / Bool.</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>uint8/uint16</code></td><td style="text-align:right;"><code>round.(UInt8, clamp.(x,0,255)) / ...</code></td><td style="text-align:right;">saturating cast</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>atan2/rot90/hex2dec/diff</code></td><td style="text-align:right;"><code>atan / rotl90 / parse(Int,_,base=16) / diff</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[X,Y]=meshgrid(x,y)</code></td><td style="text-align:right;"><code>repeat(reshape(...)) tuple</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>fft2/ifft2</code></td><td style="text-align:right;"><code>fft/ifft (FFTW)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>imread/imwrite/rgb2gray/im2double/imresize/imrotate/imfilter/imagesc</code></td><td style="text-align:right;"><code>Images.jl ecosystem (Images/ImageFiltering/ImageTransformations/Plots)</code></td><td style="text-align:right;">imwrite arg order swapped; imshow best-effort</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>anything unmapped</code></td><td style="text-align:right;"><code>name(args...) + todos entry</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>size(x)</code></td><td style="text-align:right;"><code>size(x)</code></td><td style="text-align:right;">tuple vs vector; indexing compatible</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>error(msg)</code></td><td style="text-align:right;"><code>error(msg)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>cell(n)</code></td><td style="text-align:right;"><code>Array{Any}(undef, n, n)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>plot/stem/bar/scatter/xlabel/...</code></td><td style="text-align:right;"><code>Plots.plot/sticks/bar/.../xlabel!/...</code></td><td style="text-align:right;">Plots.jl; stateful subplot/figure/hold/legend semantics are best-effort (subplot/figure still pass through)</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>fminsearch/fminunc</code></td><td style="text-align:right;"><code>Optim.minimizer(Optim.optimize(f, x0))</code></td><td style="text-align:right;">Optim.jl (unconstrained); use JuMP/Convex/MathOptInterface for constrained (linprog/quadprog) — TODO</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>conv/conv2/filter/freqz/xcorr (DSP toolbox)</code></td><td style="text-align:right;"><code>DSP.conv/DSP.filt/...</code></td><td style="text-align:right;">DSP.jl</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>butter(n,Wn)</code></td><td style="text-align:right;"><code>DSP.digitalfilter(Lowpass(Wn), Butterworth(n))</code></td><td style="text-align:right;">returns a filter object, not [b,a]; band/high types need manual work; fir1 still TODO</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>interp1/interp2</code></td><td style="text-align:right;"><code>Interpolations.linear_interpolation(...).(xq)</code></td><td style="text-align:right;">linear default, &#39;spline&#39;/&#39;cubic&#39;-&gt;cubic_spline; interp2 grids must be coordinate vectors</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>tf/ss/step/bode/lsim/c2d/feedback/pole (Control toolbox)</code></td><td style="text-align:right;"><code>ControlSystems.tf/ss/...</code></td><td style="text-align:right;">ControlSystems.jl; pole-&gt;poles; step/bode return objects, not [y,t]</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>seqcomplement/seqrcomplement/nt2aa/randseq (Bioinformatics toolbox)</code></td><td style="text-align:right;"><code>BioSequences.complement/reverse_complement/translate/randdnaseq</code></td><td style="text-align:right;">BioJulia; inputs must be BioSequences (wrap char strings, e.g. LongDNA{4}(s))</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>sparse/speye/full/nnz/nonzeros</code></td><td style="text-align:right;"><code>SparseArrays.sparse / sparse(I,n,n) / Matrix / count(!iszero,x) / nonzeros</code></td><td style="text-align:right;">SparseArrays stdlib; spdiags/accumarray/sub2ind still TODO</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>gpuArray/gather</code></td><td style="text-align:right;"><code>identity (CPU target — GPU transfer is a no-op)</code></td><td style="text-align:right;">results identical, just not offloaded</td></tr><tr><td style="text-align:right;">⬜</td><td style="text-align:right;"><code>syms / symbolic math</code></td><td style="text-align:right;"><code>—</code></td><td style="text-align:right;">Symbolic Toolbox; would need Symbolics.jl</td></tr></tbody></table><h2 id="Linear-algebra-and-arrays" tabindex="-1">Linear algebra &amp; arrays <a class="header-anchor" href="#Linear-algebra-and-arrays" aria-label="Permalink to &quot;Linear algebra &amp; arrays {#Linear-algebra-and-arrays}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>norm/dot/cross/det/diag</code></td><td style="text-align:right;"><code>norm/dot/cross/det/diag</code></td><td style="text-align:right;">LinearAlgebra</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>trace(A)</code></td><td style="text-align:right;"><code>tr(A)</code></td><td style="text-align:right;">LinearAlgebra; renamed</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>transpose(x)</code></td><td style="text-align:right;"><code>transpose(x)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>reshape(A,m,n)</code></td><td style="text-align:right;"><code>reshape(A, m, n)</code></td><td style="text-align:right;">column-major in both; <code>[]</code> dim -&gt; <code>:</code></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>fliplr/flipud/flip</code></td><td style="text-align:right;"><code>reverse(…, dims=2/1)/reverse</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>sort(x)/cumsum/cumprod</code></td><td style="text-align:right;"><code>ndims-dispatched (dims=first non-singleton for ≥2-D)</code></td><td style="text-align:right;">works for vectors and 1×N rows</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>unique(x)</code></td><td style="text-align:right;"><code>sort(unique(x))</code></td><td style="text-align:right;">MATLAB unique is sorted</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>cumsum/cumprod</code></td><td style="text-align:right;"><code>cumsum/cumprod</code></td><td style="text-align:right;">vectors; matrix needs dims</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>any(x)/all(x)</code></td><td style="text-align:right;"><code>any(x)/all(x)</code></td><td style="text-align:right;">vectors; matrix reduces per-column in MATLAB</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>mean/median/std/var</code></td><td style="text-align:right;"><code>mean/median/std/var</code></td><td style="text-align:right;">Statistics; matrix reduces per-column in MATLAB</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>gcd/lcm/factorial</code></td><td style="text-align:right;"><code>gcd.(…)/lcm.(…)/factorial.(…)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>nchoosek(n,k)</code></td><td style="text-align:right;"><code>binomial(n, k)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>kron(A,B)</code></td><td style="text-align:right;"><code>kron(A, B)</code></td><td style="text-align:right;">LinearAlgebra</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>intersect/union/setdiff</code></td><td style="text-align:right;"><code>sort(intersect/union/setdiff(…))</code></td><td style="text-align:right;">MATLAB set ops are sorted</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>ismember(a,b)</code></td><td style="text-align:right;"><code>in.(a, Ref(b))</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>tril/triu</code></td><td style="text-align:right;"><code>tril/triu</code></td><td style="text-align:right;">LinearAlgebra</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>fft/ifft/fftshift/ifftshift</code></td><td style="text-align:right;"><code>fft/ifft/fftshift/ifftshift</code></td><td style="text-align:right;">FFTW; names match</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>eig(A)</code></td><td style="text-align:right;"><code>eigvals(A)</code></td><td style="text-align:right;">LinearAlgebra; [V,D]=eig needs eigen()</td></tr></tbody></table><h2 id="Strings,-conversions-and-maps" tabindex="-1">Strings, conversions &amp; maps <a class="header-anchor" href="#Strings,-conversions-and-maps" aria-label="Permalink to &quot;Strings, conversions &amp; maps {#Strings,-conversions-and-maps}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>strcmp(a,b)</code></td><td style="text-align:right;"><code>a == b</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>strcmpi(a,b)</code></td><td style="text-align:right;"><code>lowercase(a) == lowercase(b)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>upper/lower/strtrim</code></td><td style="text-align:right;"><code>uppercase/lowercase/strip</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>strrep(s,a,b)</code></td><td style="text-align:right;"><code>replace(s, a =&gt; b)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>strcat(a,b,…)</code></td><td style="text-align:right;"><code>string(a, b, …)</code></td><td style="text-align:right;">MATLAB trims trailing whitespace of char args</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>num2str(x)</code></td><td style="text-align:right;"><code>string(x)</code></td><td style="text-align:right;">formatting/precision differs</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>str2double/str2num</code></td><td style="text-align:right;"><code>parse(Float64, x)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>contains(s,p)</code></td><td style="text-align:right;"><code>occursin(p, s)</code></td><td style="text-align:right;">arg order swapped; Octave lacks contains -&gt; not oracle-tested</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>startsWith/endsWith</code></td><td style="text-align:right;"><code>startswith/endswith</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>sprintf/fprintf</code></td><td style="text-align:right;"><code>Printf.@sprintf / Printf.@printf</code></td><td style="text-align:right;">escape/format edge cases not fully modeled</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>containers.Map(kc,vc)</code></td><td style="text-align:right;"><code>Dict(zip(kc, vc))</code></td><td style="text-align:right;">Map()-&gt;Dict(); Map(k,v)-&gt;Dict(k=&gt;v); type-param form-&gt;Dict()+TODO</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>m(k) / m(k)=v (Map)</code></td><td style="text-align:right;"><code>m[k] / m[k]=v</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>keys(m)/values(m)</code></td><td style="text-align:right;"><code>collect(keys(m))/collect(values(m))</code></td><td style="text-align:right;">MATLAB order (sorted) vs Julia (unordered)</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>isKey(m,k)/remove(m,k)</code></td><td style="text-align:right;"><code>haskey(m,k)/delete!(m,k)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>obj.method(args)</code></td><td style="text-align:right;"><code>method(obj, args...)</code></td><td style="text-align:right;">method-call syntax</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>strsplit/strjoin/deblank/fileread</code></td><td style="text-align:right;"><code>split / join / rstrip / read(_,String)</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>regexprep(s,pat,rep)</code></td><td style="text-align:right;"><code>replace(s, Regex(pat) =&gt; rep)</code></td><td style="text-align:right;">regexp itself still TODO (option-dependent API)</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>char/class/isequaln/typecast</code></td><td style="text-align:right;"><code>Char. / string(typeof(x)) / isequal / reinterpret</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>cellfun/arrayfun(f, …)</code></td><td style="text-align:right;"><code>map(f, …)</code></td><td style="text-align:right;">drops trailing &#39;UniformOutput&#39;,false</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>isa(x,&#39;type&#39;) / ischar/isnumeric/isstruct/iscell/islogical</code></td><td style="text-align:right;"><code>x isa T / eltype-based</code></td><td style="text-align:right;">approximate (MATLAB type system != Julia)</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>cell content-index c{i} / c{:} / [c{:}] / f(c{:})</code></td><td style="text-align:right;"><code>c[i] / splat c... / [c...] / f(c...)</code></td><td style="text-align:right;">{} is getindex; c{:} is a comma-separated list -&gt; splat. c{i}(j) after a brace stays a call (computed-callee ambiguity)</td></tr></tbody></table><h2 id="Control-flow-and-functions" tabindex="-1">Control flow &amp; functions <a class="header-anchor" href="#Control-flow-and-functions" aria-label="Permalink to &quot;Control flow &amp; functions {#Control-flow-and-functions}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>preallocated index loop</code></td><td style="text-align:right;"><code>comprehension y = [rhs for i in r]</code></td><td style="text-align:right;">recognized when body is y(i)=rhs, i the loop var, rhs independent of y</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>@(x) expr / @name</code></td><td style="text-align:right;"><code>x -&gt; expr / name</code></td><td style="text-align:right;">anonymous functions; lambda params are scoped so x(i) inside is indexing</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>function-handle parameter f(x)</code></td><td style="text-align:right;"><code>f(x) (kept a call, not f[x])</code></td><td style="text-align:right;">heuristic: a param used only as a call-like callee; a read-only array param sized only by indexing may misclassify (loud error, not silent)</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>command syntax (clc, format …)</code></td><td style="text-align:right;"><code>dropped (no Julia equivalent)</code></td><td style="text-align:right;">recorded as a todo</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>if/elseif/else/end</code></td><td style="text-align:right;"><code>if/elseif/else/end</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>for v = expr ... end</code></td><td style="text-align:right;"><code>for v in expr ... end</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>while c ... end</code></td><td style="text-align:right;"><code>while c ... end</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>break / continue / return</code></td><td style="text-align:right;"><code>break / continue / return</code></td><td style="text-align:right;">early <code>return</code> carries the function&#39;s outputs</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>switch/case/otherwise</code></td><td style="text-align:right;"><code>if/elseif/else</code></td><td style="text-align:right;"><code>case {a,b}</code> -&gt; `sv == a</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>try/catch e</code></td><td style="text-align:right;"><code>try/catch e</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>function y = f(a,b)</code></td><td style="text-align:right;"><code>function f(a, b) ... return y end</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>function [u,v] = f(...)</code></td><td style="text-align:right;"><code>... return (u, v) end</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>varargin / varargin{i}</code></td><td style="text-align:right;"><code>varargin... / varargin[i]</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>nargin</code></td><td style="text-align:right;"><code>computed prologue + optional params</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>nargout</code></td><td style="text-align:right;"><code>nargout = &lt;#declared outputs&gt;</code></td><td style="text-align:right;">assumes all outputs requested (Julia has no caller arity)</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>single-line ;-separated control flow</code></td><td style="text-align:right;"><code>—</code></td><td style="text-align:right;">grammar emits ERROR; use newlines (flagged via has_error)</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[~, x] = f(...)</code></td><td style="text-align:right;"><code>(_, x) = ...</code></td><td style="text-align:right;">~ ignored-output placeholder kept in position</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>global x y</code></td><td style="text-align:right;"><code>global x, y (shared module-level state)</code></td><td style="text-align:right;">persistent still dropped (function-static; needs a Ref/closure)</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[a,b,c]=deal(x) / [a,b]=deal(p,q)</code></td><td style="text-align:right;"><code>(a,b,c)=(x,x,x) / (a,b)=(p,q)</code></td><td style="text-align:right;">distributes inputs to outputs</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>[m,i]=max(v) / [m,i]=min(v) / [s,p]=sort(v)</code></td><td style="text-align:right;"><code>findmax / findmin / (sort(v), sortperm(v))</code></td><td style="text-align:right;">output-arity-dependent; vector index is Int (matrix max index -&gt; CartesianIndex differs)</td></tr></tbody></table><h2 id="Scripts-vs-functions" tabindex="-1">Scripts vs functions <a class="header-anchor" href="#Scripts-vs-functions" aria-label="Permalink to &quot;Scripts vs functions {#Scripts-vs-functions}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>script with a top-level loop</code></td><td style="text-align:right;"><code>body wrapped in let ... end</code></td><td style="text-align:right;">Julia soft-scope rule</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>function file</code></td><td style="text-align:right;"><code>top-level functions (hoisted ahead of script code)</code></td><td style="text-align:right;"></td></tr></tbody></table><h2 id="classdef" tabindex="-1">classdef <a class="header-anchor" href="#classdef" aria-label="Permalink to &quot;classdef {#classdef}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;"></th><th style="text-align:right;">MATLAB</th><th style="text-align:right;">Julia</th><th style="text-align:right;">Notes</th></tr></thead><tbody><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>classdef C</code></td><td style="text-align:right;"><code>abstract type AbstractC + mutable struct C &lt;: AbstractC + @contract/@verify via BaseTypeContracts</code></td><td style="text-align:right;">instance methods become a @contract on the abstract type; @verify C enforces method existence at precompile time; property-only classes skip @contract/@verify</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>properties</code></td><td style="text-align:right;"><code>struct fields</code></td><td style="text-align:right;">defaults applied in the constructor</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>constructor function obj = C(...)</code></td><td style="text-align:right;"><code>inner constructor using new()</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>method function r = m(obj,...)</code></td><td style="text-align:right;"><code>function m(obj::C, ...) + forward-decl</code>function m end<code>+ contract entry m(::Self, ::Any...)::Any</code></td><td style="text-align:right;"></td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>operator methods plus/minus/mtimes/eq/lt/uminus/transpose/horzcat/...</code></td><td style="text-align:right;"><code>extend Base.:+ / :- / :* / :(==) / :&lt; / unary :- / transpose / hcat ...</code></td><td style="text-align:right;">so a+b, a==b, -a, a&#39; dispatch; operator overloads excluded from @contract (not named-interface methods); elementwise times/rdivide/power left as plain methods (route via *)</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>disp(obj) / display(obj)</code></td><td style="text-align:right;"><code>Base.show(io::IO, obj::C)</code></td><td style="text-align:right;">io injected; body prints redirected (fprintf -&gt; @printf io, disp -&gt; println(io,…)); excluded from @contract; integrates with print/string/REPL</td></tr><tr><td style="text-align:right;">✅</td><td style="text-align:right;"><code>obj.prop(i) where prop is a property</code></td><td style="text-align:right;"><code>obj.prop[i] (index), not prop(obj, i)</code></td><td style="text-align:right;">tracked property names distinguish indexed-property access from method calls</td></tr><tr><td style="text-align:right;">⬜</td><td style="text-align:right;"><code>subsref / subsasgn (custom () {} . indexing)</code></td><td style="text-align:right;"><code>—</code></td><td style="text-align:right;">MATLAB substruct protocol (s.type/s.subs dispatch) not modeled</td></tr><tr><td style="text-align:right;">🟡</td><td style="text-align:right;"><code>classdef C &lt; S</code></td><td style="text-align:right;"><code>abstract type AbstractC &lt;: AbstractS</code></td><td style="text-align:right;">inheritance only when S converted in the same unit</td></tr><tr><td style="text-align:right;">⬜</td><td style="text-align:right;"><code>struct arrays / events / Access= attrs</code></td><td style="text-align:right;"><code>—</code></td><td style="text-align:right;"></td></tr></tbody></table>',23)])])}const y=e(r,[["render",a]]);export{x as __pageData,y as default};
